const MaskEditor = ({ imageUrl, onSave, onCancel }: { imageUrl: string, onSave: (mask: string) => void, onCancel: () => void }) => {
  const imageCanvasRef = useRef<HTMLCanvasElement>(null);
  const maskCanvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(30);

  useEffect(() => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = imageUrl;
    img.onload = () => {
      const maxWidth = 800;
      const maxHeight = 600;
      let width = img.width;
      let height = img.height;

      if (width > maxWidth) {
        height = (maxWidth / width) * height;
        width = maxWidth;
      }
      if (height > maxHeight) {
        width = (maxHeight / height) * width;
        height = maxHeight;
      }

      const imgCanvas = imageCanvasRef.current;
      const mskCanvas = maskCanvasRef.current;
      if (imgCanvas && mskCanvas) {
        imgCanvas.width = width;
        imgCanvas.height = height;
        mskCanvas.width = width;
        mskCanvas.height = height;

        const iCtx = imgCanvas.getContext('2d');
        if (iCtx) {
          iCtx.drawImage(img, 0, 0, width, height);
        }
      }
    };
  }, [imageUrl]);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    draw(e);
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    const canvas = maskCanvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) ctx.beginPath();
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const canvas = maskCanvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    let x, y;
    if ('touches' in e) {
      x = e.touches[0].clientX - rect.left;
      y = e.touches[0].clientY - rect.top;
    } else {
      x = e.clientX - rect.left;
      y = e.clientY - rect.top;
    }

    ctx.lineWidth = brushSize;
    ctx.lineCap = 'round';
    ctx.strokeStyle = 'rgba(255, 0, 0, 0.6)'; // Red mask for visualization

    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const handleSave = () => {
    const canvas = maskCanvasRef.current;
    if (!canvas) return;
    
    // Create a final mask (black background, white mask)
    const finalCanvas = document.createElement('canvas');
    finalCanvas.width = canvas.width;
    finalCanvas.height = canvas.height;
    const fCtx = finalCanvas.getContext('2d');
    if (!fCtx) return;

    fCtx.fillStyle = 'black';
    fCtx.fillRect(0, 0, finalCanvas.width, finalCanvas.height);

    const maskData = canvas.getContext('2d')?.getImageData(0, 0, canvas.width, canvas.height);
    if (maskData) {
      const data = maskData.data;
      for (let i = 0; i < data.length; i += 4) {
        const alpha = data[i+3];
        if (alpha > 0) {
          data[i] = 255;
          data[i+1] = 255;
          data[i+2] = 255;
          data[i+3] = 255;
        } else {
          data[i] = 0;
          data[i+1] = 0;
          data[i+2] = 0;
          data[i+3] = 255;
        }
      }
      fCtx.putImageData(maskData, 0, 0);
    }
    
    onSave(finalCanvas.toDataURL('image/png'));
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center p-4">
      <div className="bg-[#1a1a1a] border border-white/10 rounded-2xl p-6 w-full max-w-4xl space-y-6 shadow-2xl">
        <div className="flex items-center justify-between">
          <h3 className="text-xl font-bold text-white">Khoanh vùng chỉnh sửa (Mask Editor)</h3>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <span className="text-xs text-white/40 uppercase">Cỡ cọ:</span>
              <input 
                type="range" 
                min="5" 
                max="100" 
                value={brushSize} 
                onChange={(e) => setBrushSize(parseInt(e.target.value))}
                className="w-32 accent-accent-cyan"
              />
            </div>
            <button 
              onClick={() => {
                const ctx = maskCanvasRef.current?.getContext('2d');
                if (ctx) ctx.clearRect(0, 0, maskCanvasRef.current!.width, maskCanvasRef.current!.height);
              }}
              className="px-3 py-1 text-xs text-white/60 hover:text-white border border-white/10 rounded-lg hover:bg-white/5 transition-all"
            >
              Xóa hết
            </button>
            <button onClick={onCancel} className="p-2 hover:bg-white/5 rounded-lg text-white/60 transition-colors">
              <X size={20} />
            </button>
          </div>
        </div>

        <div className="relative bg-black rounded-xl overflow-hidden cursor-crosshair flex items-center justify-center border border-white/5 min-h-[400px]">
          <canvas 
            ref={imageCanvasRef}
            className="absolute"
          />
          <canvas 
            ref={maskCanvasRef}
            onMouseDown={startDrawing}
            onMouseMove={draw}
            onMouseUp={stopDrawing}
            onMouseLeave={stopDrawing}
            onTouchStart={startDrawing}
            onTouchMove={draw}
            onTouchEnd={stopDrawing}
            className="absolute z-10 touch-none"
          />
        </div>

        <div className="flex justify-end gap-3">
          <button 
            onClick={onCancel}
            className="px-6 py-2 rounded-xl text-white/60 hover:bg-white/5 transition-colors font-bold"
          >
            Hủy bỏ
          </button>
          <button 
            onClick={handleSave}
            className="px-8 py-2 bg-accent-cyan text-black rounded-xl font-bold hover:bg-accent-cyan/80 transition-colors"
          >
            Xác nhận vùng chọn
          </button>
        </div>
      </div>
    </div>
  );
};

